<?php include 'includes/config.php'; require_role('buyer'); $u=current_user(); $cart=$_SESSION['cart']??[]; if(!$cart) die('Cart empty. <a href="products.php">Shop products</a>');
$items=[];$total=0;$seller_id=null;$brand_id=null;foreach($cart as $pid=>$qty){$stmt=$pdo->prepare('SELECT * FROM products WHERE id=?');$stmt->execute([$pid]);$p=$stmt->fetch(PDO::FETCH_ASSOC);if($p){$items[]=['p'=>$p,'qty'=>$qty];$total+=$p['price']*$qty;$seller_id=$p['seller_id'];$brand_id=$p['brand_id'];}}
$pay=$pdo->prepare('SELECT bank_name,account_holder,account_number FROM seller_payment_details WHERE seller_id=?');$pay->execute([$seller_id]);$payment=$pay->fetch(PDO::FETCH_ASSOC);
if($_SERVER['REQUEST_METHOD']==='POST'){$method=clean($_POST['delivery_method']);$addr=clean($_POST['buyer_address']);$pep=clean($_POST['pep_collection_point']);$proof=upload_file($_FILES['proof']??null,'uploads/proofs');
 $pdo->prepare('INSERT INTO orders(buyer_id,seller_id,brand_id,total,delivery_method,buyer_address,pep_collection_point,proof_path,status) VALUES(?,?,?,?,?,?,?,?,?)')->execute([$u['id'],$seller_id,$brand_id,$total,$method,$addr,$pep,$proof,'proof_uploaded']);$oid=$pdo->lastInsertId();
 foreach($items as $it){$pdo->prepare('INSERT INTO order_items(order_id,product_id,quantity,price) VALUES(?,?,?,?)')->execute([$oid,$it['p']['id'],$it['qty'],$it['p']['price']]);}
 unset($_SESSION['cart']); header('Location: buyer-orders.php'); exit;}
?><!DOCTYPE html><html><head><title>Checkout</title><link rel="stylesheet" href="css/styles.css"></head><body><?php include 'includes/header.php'; ?><form class="form-shell" method="post" enctype="multipart/form-data"><h1>Checkout</h1><p class="price">Total: R<?= number_format($total,2) ?></p><?php if($payment): ?><div class="card"><h3>Pay Seller</h3><p>Bank: <?= clean($payment['bank_name']) ?></p><p>Account Holder: <?= clean($payment['account_holder']) ?></p><p>Account Number: <?= clean($payment['account_number']) ?></p></div><?php else: ?><p class="muted">Seller has not added payment details yet.</p><?php endif; ?><br><div class="field"><label>Delivery Method</label><select name="delivery_method"><option value="pep_collection">PEP Collection</option><option value="collect_at_brand">Collect at Brand</option></select></div><div class="field"><label>Your Address</label><textarea name="buyer_address"></textarea></div><div class="field"><label>Nearest PEP / Collection Point</label><input name="pep_collection_point" placeholder="Example: PEP Vaal Mall"></div><div class="field"><label>Upload Proof of Payment</label><input type="file" name="proof" required></div><button>Submit Order</button></form></body></html>
